import { useState } from "react";
import { Link } from "react-router-dom";
import axios from 'axios';
import { useNavigate } from "react-router-dom";
import "./Siderbar.css.css";

function Register() {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const navigate = useNavigate();


  const handleRegister = (e) => {
    e.preventDefault();
    if (!name || !email || !password) {
      setError("All fields are required");
      return;
    }
    if (!email.toLowerCase().endsWith("@gmail.com")) {
      setError("Email must be Gmail only");
      return;
    }
    setError("");
    axios.post('http://localhost:5000/register', { name, email, password })
      .then(result =>{console.log(result)
      navigate('/login')
      })
      .catch(err => console.log(err));
  };

  const handleEnter = (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      const form = e.target.form;
      const index = Array.prototype.indexOf.call(form, e.target);
      if (index === 2) {
        handleRegister();
      } else {
        form.elements[index + 1].focus();
      }
    }
  };

  return (
    <form className="form" onSubmit={(e) => e.preventDefault()}>
      <div className="authbox">
        <h2>Register</h2>
        {/* USERNAME */}
        <input type="name" placeholder="Username" value={name} onChange={(e) => setName(e.target.value)} onKeyDown={handleEnter} />
        {/* EMAIL */}
        <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} onKeyDown={handleEnter} />
        {/* PASSWORD */}
        <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} onKeyDown={handleEnter} />
    
        {error && <p style={{ color: "red" }}>{error}</p>}
        {/* LOGIN LINK */}
        <p> Already have account? <Link to="/">Login</Link> </p>
        {/* BUTTON */}
        <button type="button" onClick={handleRegister}> Register </button>
      </div>
    </form>
  );
}

export default Register;
